public static ETGSalesOrderFixationDP construct()
{
    ETGSalesOrderFixationDP  dataProvider;

    dataProvider = new ETGSalesOrderFixationDP();

    return dataProvider;
}

public ETGSalesOrderFixationTmp processReport (ETGSalesOrderFixationContract _contract)
{
    SalesId            salesId;
    SalesTable         salesTable;

    salesId     =   _contract.parmSalesId();
    salesTable  =   SalesTable::find(salesId);

    salesOrderFixationTmp.SalesId               =   salesTable.SalesId;
    salesOrderFixationTmp.CustAccount           =   salesTable.CustAccount;
    salesOrderFixationTmp.SalesOrderHeaderRecId =   salesTable.RecId;

    ttsbegin;
    salesOrderFixationTmp.insert();
    ttscommit;

    // Select all rows from tmp table and return
    select salesOrderFixationTmp;
    return salesOrderFixationTmp;
}
